// Auto-migrated from the original static guide HTML. Structural markup
// and code samples are preserved; inline styles, scripts, and the guide's
// own bespoke syntax-highlight token classes were stripped so every guide
// renders through the one shared GuideReader stylesheet.
export const html: string = "<section class=\"step\" id=\"s1\">\n<div class=\"step-header\">\n<div class=\"step-badge\">01</div>\n<h2>Dev vs production mindset</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Most production incidents trace back to a development habit that quietly carried over. Knowing the differences up front prevents the most expensive class of mistakes.</div>\n<div class=\"step-body\">\n<p>Django's <code>runserver</code> is explicitly documented as unfit for production. It is single-threaded, auto-reloads on file changes, serves static files for convenience, and shows full stack traces to anyone who hits an error. None of that belongs on a public server.</p>\n</div>\n<table>\n<tr><th>Concern</th><th>Development</th><th>Production</th></tr>\n<tr><td>Server</td><td><code>python manage.py runserver</code></td><td>Gunicorn/uWSGI behind Nginx</td></tr>\n<tr><td>DEBUG</td><td><code>True</code></td><td><code>False</code>, always</td></tr>\n<tr><td>Database</td><td>SQLite file</td><td>PostgreSQL, managed or self-hosted</td></tr>\n<tr><td>Static files</td><td>Served automatically by Django</td><td>Served by Nginx, Whitenoise, or a CDN</td></tr>\n<tr><td>Secrets</td><td>Hardcoded or in a local .env</td><td>Environment variables / secrets manager</td></tr>\n<tr><td>Errors</td><td>Full traceback in browser</td><td>Generic error page, logged to Sentry/file</td></tr>\n<tr><td>HTTPS</td><td>Usually plain HTTP on localhost</td><td>Enforced TLS everywhere</td></tr>\n</table>\n<div>Treat this guide as a checklist to walk through once, then a reference to revisit before every major release. Nothing here is optional for a real public-facing project, each step closes a specific, well-known failure mode.</div>\n</section>\n<section class=\"step\" id=\"s2\">\n<div class=\"step-header\">\n<div class=\"step-badge\">02</div>\n<h2>Split settings properly</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>A single settings.py with manual edits before every deploy is how DEBUG=True ends up in production by accident. Splitting settings removes that human error entirely.</div>\n<div class=\"step-body\">\n<p>The cleanest pattern is a <code>settings/</code> package with a shared base and environment-specific overrides, selected by an environment variable.</p>\n</div>\n<div class=\"tree\">\n<span>core/</span>\n \u2514\u2500\u2500 <span>settings/</span>\n \u251c\u2500\u2500 <span>__init__.py</span>\n \u251c\u2500\u2500 <span>base.py</span> <span># shared by every environment</span>\n \u251c\u2500\u2500 <span>development.py</span> <span># DEBUG=True, local DB, console email</span>\n \u2514\u2500\u2500 <span>production.py</span> <span># DEBUG=False, hardened, real services</span></div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">core/settings/development.py</span>\n</div>\n<pre><span>from</span> .base <span>import</span> *\n\nDEBUG = <span>True</span>\nALLOWED_HOSTS = [<span>\"localhost\"</span>, <span>\"127.0.0.1\"</span>]\nEMAIL_BACKEND = <span>\"django.core.mail.backends.console.EmailBackend\"</span>\n\nDATABASES = {\n <span>\"default\"</span>: {\n <span>\"ENGINE\"</span>: <span>\"django.db.backends.sqlite3\"</span>,\n <span>\"NAME\"</span>: BASE_DIR / <span>\"db.sqlite3\"</span>,\n }\n}</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">core/settings/production.py</span>\n</div>\n<pre><span>from</span> .base <span>import</span> *\n<span>import</span> dj_database_url\n\nDEBUG = <span>False</span>\nALLOWED_HOSTS = config(<span>\"ALLOWED_HOSTS\"</span>, cast=<span>lambda</span> v: v.split(<span>\",\"</span>))\n\nDATABASES = {\n <span>\"default\"</span>: dj_database_url.<span>config</span>(default=config(<span>\"DATABASE_URL\"</span>), conn_max_age=<span>600</span>)\n}\n\nSECURE_SSL_REDIRECT = <span>True</span>\nSESSION_COOKIE_SECURE = <span>True</span>\nCSRF_COOKIE_SECURE = <span>True</span></pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n</div>\n<pre><span># tell manage.py and wsgi.py which settings module to use</span>\nexport DJANGO_SETTINGS_MODULE=core.settings.production\ngunicorn core.wsgi:application</pre>\n</div>\n<div class=\"tone-danger\"><strong>Common mistake:</strong> a single settings.py with an <code>if os.environ.get(\"PROD\")</code> branch scattered throughout. It works, but it is far easier to leave a flag unset by accident than to forget to set <code>DJANGO_SETTINGS_MODULE</code>, which fails loudly instead of silently.</div>\n</section>\n<section class=\"step\" id=\"s3\">\n<div class=\"step-header\">\n<div class=\"step-badge\">03</div>\n<h2>Environment variables</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Secrets and per-environment config (database URLs, API keys, debug flags) should never live in version control. Environment variables are the standard mechanism to keep them out.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n</div>\n<pre>pip install python-decouple\npip freeze &gt; requirements.txt</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Text</span>\n<span class=\"code-file\">.env (local only, never committed)</span>\n</div>\n<pre>SECRET_KEY=django-insecure-change-me-in-production\nDEBUG=True\nALLOWED_HOSTS=localhost,127.0.0.1\nDATABASE_URL=sqlite:///db.sqlite3\nEMAIL_HOST_PASSWORD=\nSENTRY_DSN=</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Text</span>\n<span class=\"code-file\">.gitignore</span>\n</div>\n<pre>.env\n*.pyc\n__pycache__/\ndb.sqlite3\n/staticfiles/\n/media/\nvenv/\n.DS_Store</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">core/settings/base.py</span>\n</div>\n<pre><span>from</span> decouple <span>import</span> config\n<span>from</span> pathlib <span>import</span> Path\n\nBASE_DIR = Path(__file__).resolve().parent.parent.parent\nSECRET_KEY = config(<span>\"SECRET_KEY\"</span>)\nDEBUG = config(<span>\"DEBUG\"</span>, default=<span>False</span>, cast=bool)</pre>\n</div>\n<div class=\"tone-danger\"><strong>Critical:</strong> if <code>.env</code> was ever committed to git in the past, rotating the leaked secrets is not optional, they remain in git history forever even after deleting the file. Use <code>git filter-repo</code> or BFG Repo-Cleaner to scrub history, then rotate every exposed credential.</div>\n<div class=\"tone-tip\"><strong>Tip:</strong> commit a <code>.env.example</code> file with the variable names but no real values, so the next developer (or future you) knows exactly what needs to be set.</div>\n</section>\n<section class=\"step\" id=\"s4\">\n<div class=\"step-header\">\n<div class=\"step-badge\">04</div>\n<h2>requirements.txt discipline</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Unpinned dependencies mean your production server can install a different package version than the one you tested locally, a frequent source of \"works on my machine\" deploy failures.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n</div>\n<pre><span># always pin exact versions before deploying</span>\npip freeze &gt; requirements.txt</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Text</span>\n<span class=\"code-file\">requirements.txt</span>\n</div>\n<pre>Django==5.0.6\ngunicorn==22.0.0\npsycopg2-binary==2.9.9\ndj-database-url==2.2.0\npython-decouple==3.8\nwhitenoise==6.7.0\nsentry-sdk==2.5.1</pre>\n</div>\n<div class=\"step-body\">\n<p>For larger teams, split into <code>requirements/base.txt</code>, <code>requirements/dev.txt</code> (adds debug-toolbar, pytest), and <code>requirements/production.txt</code>, mirroring the settings split from Step 2.</p>\n</div>\n<div class=\"tone-tip\"><strong>Tip:</strong> run <code>pip install pip-audit</code> and <code>pip-audit</code> periodically, or enable Dependabot/Renovate on the repository, to catch known vulnerabilities in your dependency tree before they reach production.</div>\n</section>\n<section class=\"step\" id=\"s5\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-tip\">05</div>\n<h2>SECRET_KEY and ALLOWED_HOSTS</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>These two settings are the most basic gate against impersonation and host-header attacks. Getting them wrong fully undermines session and CSRF protection.</div>\n<div class=\"step-body\">\n<p>SECRET_KEY signs sessions, password reset tokens, and CSRF tokens. If it leaks, an attacker can forge sessions for any user. Generate a fresh, long, random key for every project and every environment, never reuse the one Django scaffolds by default.</p>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n<span class=\"code-file\">generate a strong key</span>\n</div>\n<pre>python -c <span>\"from django.core.management.utils import get_random_secret_key; print(get_random_secret_key())\"</span></pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n</div>\n<pre>ALLOWED_HOSTS = [<span>\"yourdomain.com\"</span>, <span>\"www.yourdomain.com\"</span>]\n<span># never use [\"*\"] in production, it disables host header validation entirely</span></pre>\n</div>\n<div class=\"tone-danger\"><strong>Critical:</strong> <code>ALLOWED_HOSTS = [\"*\"]</code> in production opens the door to host header poisoning, which can break password reset emails and cache poisoning attacks. List only the exact domains your app should respond to.</div>\n</section>\n<section class=\"step\" id=\"s6\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-tip\">06</div>\n<h2>HTTPS and SSL settings</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Without these flags, cookies and form submissions can be intercepted over plain HTTP even if a TLS certificate exists, because Django itself does not enforce the upgrade.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">core/settings/production.py</span>\n</div>\n<pre>SECURE_SSL_REDIRECT = <span>True</span> <span># force HTTP requests to redirect to HTTPS</span>\nSESSION_COOKIE_SECURE = <span>True</span> <span># session cookie only sent over HTTPS</span>\nCSRF_COOKIE_SECURE = <span>True</span> <span># CSRF cookie only sent over HTTPS</span>\nSECURE_HSTS_SECONDS = <span>31536000</span> <span># tell browsers to remember HTTPS-only for 1 year</span>\nSECURE_HSTS_INCLUDE_SUBDOMAINS = <span>True</span>\nSECURE_HSTS_PRELOAD = <span>True</span>\nSECURE_PROXY_SSL_HEADER = (<span>\"HTTP_X_FORWARDED_PROTO\"</span>, <span>\"https\"</span>)</pre>\n</div>\n<div>The last line is required whenever Django sits behind a reverse proxy or load balancer (Nginx, a PaaS router) that terminates TLS itself and forwards plain HTTP internally. Without it, Django thinks every request is insecure and can get stuck in an infinite redirect loop.</div>\n<div class=\"tone-danger\"><strong>Common mistake:</strong> setting <code>SECURE_HSTS_SECONDS</code> to a large value before confirming HTTPS actually works end to end. Once a browser receives that header, it refuses to load the site over HTTP for the full duration, even if you misconfigured the certificate. Test with a small value first, like 60, then raise it.</div>\n</section>\n<section class=\"step\" id=\"s7\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-tip\">07</div>\n<h2>Security middleware and headers</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>A handful of extra response headers close common browser-side attack vectors (clickjacking, MIME sniffing, XSS) with almost no engineering effort.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">core/settings/production.py</span>\n</div>\n<pre>X_FRAME_OPTIONS = <span>\"DENY\"</span> <span># block the site from being framed (clickjacking)</span>\nSECURE_CONTENT_TYPE_NOSNIFF = <span>True</span> <span># stop browsers from guessing content types</span>\nSECURE_REFERRER_POLICY = <span>\"same-origin\"</span>\nCSRF_TRUSTED_ORIGINS = [<span>\"https://yourdomain.com\"</span>]</pre>\n</div>\n<div class=\"step-body\">\n<p>If sessions or auth cookies need to survive across subdomains, set the cookie domain explicitly. Otherwise leave it unset, Django defaults to the current host only, which is the safer default.</p>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n</div>\n<pre>SESSION_COOKIE_HTTPONLY = <span>True</span> <span># default; blocks JS access to the session cookie</span>\nSESSION_COOKIE_SAMESITE = <span>\"Lax\"</span> <span># or \"Strict\" for stricter cross-site protection</span>\nCSRF_COOKIE_HTTPONLY = <span>False</span> <span># must stay False so JS can read it for AJAX headers</span></pre>\n</div>\n<div class=\"tone-tip\"><strong>Tip:</strong> add a Content-Security-Policy header with <code>django-csp</code> for a much stronger layer of XSS protection, it restricts which domains scripts, styles, and images are allowed to load from.</div>\n</section>\n<section class=\"step\" id=\"s8\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-tip\">08</div>\n<h2>check --deploy</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Django ships a built-in command that audits your settings against known production best practices. Running it is faster and more reliable than manually re-checking every flag above.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n</div>\n<pre>DJANGO_SETTINGS_MODULE=core.settings.production python manage.py check --deploy</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Text</span>\n<span class=\"code-file\">Example output before fixes</span>\n</div>\n<pre>System check identified some issues:\n\nWARNINGS:\n?: (security.W004) You have not set SECURE_HSTS_SECONDS.\n?: (security.W008) Your SECURE_SSL_REDIRECT setting is not set to True.\n?: (security.W012) SESSION_COOKIE_SECURE is not set to True.\n?: (security.W018) You should not have DEBUG set to True in deployment.\n\nSystem check identified 4 issues (0 silenced).</pre>\n</div>\n<div>Run this command as a required step in your deploy pipeline (see Step 18), not just manually. A zero-warning result before every release is the single highest-leverage security habit on this entire page.</div>\n</section>\n<section class=\"step\" id=\"s9\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-info\">09</div>\n<h2>SQLite to PostgreSQL</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>SQLite is file-based and effectively single-writer. The moment you have more than one Gunicorn worker writing concurrently, SQLite becomes a bottleneck and a source of lock errors.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n</div>\n<pre>pip install psycopg2-binary dj-database-url\npip freeze &gt; requirements.txt</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">core/settings/production.py</span>\n</div>\n<pre><span>import</span> dj_database_url\n\nDATABASES = {\n <span>\"default\"</span>: dj_database_url.<span>config</span>(\n default=config(<span>\"DATABASE_URL\"</span>),\n conn_max_age=<span>600</span>,\n ssl_require=<span>True</span>,\n )\n}</pre>\n</div>\n<div class=\"step-body\">\n<p>Migrating existing data from SQLite to PostgreSQL once the new database is provisioned:</p>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n</div>\n<pre><span># 1. dump data while still pointed at SQLite</span>\npython manage.py dumpdata --natural-foreign --natural-primary -e contenttypes -e auth.Permission &gt; data.json\n\n<span># 2. point DATABASE_URL at the new PostgreSQL instance, then run migrations</span>\npython manage.py migrate\n\n<span># 3. load the data into the fresh PostgreSQL schema</span>\npython manage.py loaddata data.json</pre>\n</div>\n<div class=\"tone-danger\"><strong>Common mistake:</strong> dumping with content types and permissions included. They are regenerated automatically by <code>migrate</code> and including them in the dump usually causes integrity errors on load, the <code>-e</code> excludes above sidestep that.</div>\n</section>\n<section class=\"step\" id=\"s10\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-info\">10</div>\n<h2>Migrations in production</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Running migrations against a live database with real traffic is fundamentally different from running them on an empty local database. A wrong migration can lock a table for minutes or drop data irreversibly.</div>\n<div class=\"step-body\">\n<p>Best practices before applying a migration to production:</p>\n</div>\n<div class=\"checklist\">\n<div class=\"check-item\"><div class=\"check-box\"></div><span>Run <code>python manage.py makemigrations --check --dry-run</code> in CI to catch missing migrations before merge</span></div>\n<div class=\"check-item\"><div class=\"check-box\"></div><span>Review every auto-generated migration file, do not trust it blindly, especially for column drops or renames</span></div>\n<div class=\"check-item\"><div class=\"check-box\"></div><span>Take a database backup or snapshot immediately before migrating production</span></div>\n<div class=\"check-item\"><div class=\"check-box\"></div><span>For large tables, add columns as nullable first, backfill data, then add the NOT NULL constraint in a second migration</span></div>\n<div class=\"check-item\"><div class=\"check-box\"></div><span>Avoid renaming a column and changing its type in the same migration, split into separate steps</span></div>\n<div class=\"check-item\"><div class=\"check-box\"></div><span>Run <code>python manage.py migrate --plan</code> first to preview exactly what will execute</span></div>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n</div>\n<pre>python manage.py migrate --plan <span># dry-run preview, no changes applied</span>\npython manage.py migrate <span># apply for real</span></pre>\n</div>\n<div class=\"tone-danger\"><strong>Critical:</strong> never run <code>migrate</code> automatically as part of a rolling deploy without a backup step before it. A bad migration combined with no recent backup is one of the few classes of incident with no clean rollback path.</div>\n</section>\n<section class=\"step\" id=\"s11\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-info\">11</div>\n<h2>Backups and restore</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>A backup strategy you have never tested restoring from is not a backup strategy. This is the single most skipped step in small projects, and the most costly when skipped.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n<span class=\"code-file\">Manual PostgreSQL backup and restore</span>\n</div>\n<pre><span># backup</span>\npg_dump --no-owner --format=custom $DATABASE_URL &gt; backup_$(date +%Y%m%d).dump\n\n<span># restore into a fresh database</span>\npg_restore --no-owner --clean --dbname=$DATABASE_URL backup_20260101.dump</pre>\n</div>\n<div class=\"step-body\">\n<p>Most managed database providers (Railway, Render, RDS, Supabase) offer automated daily snapshots. Confirm yours is enabled, then go one step further:</p>\n</div>\n<div class=\"checklist\">\n<div class=\"check-item\"><div class=\"check-box\"></div><span>Verify the retention window matches your needs, daily for 7 days is a common minimum</span></div>\n<div class=\"check-item\"><div class=\"check-box\"></div><span>Actually perform a restore into a staging environment at least once, do not assume it works</span></div>\n<div class=\"check-item\"><div class=\"check-box\"></div><span>Store at least one backup copy outside the primary provider, in case the provider itself has an outage</span></div>\n<div class=\"check-item\"><div class=\"check-box\"></div><span>Back up uploaded media files separately, database backups do not include files on disk or in object storage</span></div>\n</div>\n</section>\n<section class=\"step\" id=\"s12\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-info\">12</div>\n<h2>collectstatic and Whitenoise</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Django stops serving static files itself once DEBUG is False. Something else has to take over, and Whitenoise is the simplest option that needs no separate web server config.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n</div>\n<pre>pip install whitenoise\npip freeze &gt; requirements.txt</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">core/settings/production.py</span>\n</div>\n<pre>MIDDLEWARE = [\n <span>\"django.middleware.security.SecurityMiddleware\"</span>,\n <span>\"whitenoise.middleware.WhiteNoiseMiddleware\"</span>, <span># right after SecurityMiddleware</span>\n <span># ... rest of default middleware ...</span>\n]\n\nSTATICFILES_STORAGE = <span>\"whitenoise.storage.CompressedManifestStaticFilesStorage\"</span>\n<span># adds content hashes to filenames for safe, aggressive browser caching</span></pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n<span class=\"code-file\">Run before every deploy</span>\n</div>\n<pre>python manage.py collectstatic --noinput</pre>\n</div>\n<div>With the manifest storage backend, <code>{% static 'css/base.css' %}</code> automatically resolves to something like <code>css/base.a3f9c1.css</code>. The hash changes whenever the file content changes, which lets you set far-future cache headers safely, browsers fetch a new file whenever the hash changes instead of serving stale cached CSS.</div>\n<div class=\"tone-tip\"><strong>Tip:</strong> for higher-traffic sites, move static assets to a CDN (Cloudflare, AWS CloudFront, S3 plus CloudFront) instead of serving them from the app server at all. Whitenoise is excellent up to moderate traffic, a CDN takes the load off your server entirely beyond that.</div>\n</section>\n<section class=\"step\" id=\"s13\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-info\">13</div>\n<h2>Media files and object storage</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>User-uploaded files saved to local disk vanish on most modern hosting platforms, since containers are ephemeral and redeployed from scratch on every release.</div>\n<div class=\"step-body\">\n<p>Store media files in object storage (S3, Cloudflare R2, Backblaze B2) instead of the local filesystem in production, using <code>django-storages</code>.</p>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n</div>\n<pre>pip install django-storages boto3\npip freeze &gt; requirements.txt</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">core/settings/production.py</span>\n</div>\n<pre>INSTALLED_APPS += [<span>\"storages\"</span>]\n\nDEFAULT_FILE_STORAGE = <span>\"storages.backends.s3boto3.S3Boto3Storage\"</span>\nAWS_STORAGE_BUCKET_NAME = config(<span>\"AWS_STORAGE_BUCKET_NAME\"</span>)\nAWS_S3_REGION_NAME = config(<span>\"AWS_S3_REGION_NAME\"</span>, default=<span>\"us-east-1\"</span>)\nAWS_ACCESS_KEY_ID = config(<span>\"AWS_ACCESS_KEY_ID\"</span>)\nAWS_SECRET_ACCESS_KEY = config(<span>\"AWS_SECRET_ACCESS_KEY\"</span>)\nAWS_S3_FILE_OVERWRITE = <span>False</span>\nAWS_DEFAULT_ACL = <span>None</span></pre>\n</div>\n<div>No changes are needed in templates or models. <code>{{ post.thumbnail.url }}</code> continues to work exactly as before, it now points to the S3 URL instead of a local path, because Django's storage abstraction handles that transparently.</div>\n<div class=\"tone-danger\"><strong>Common mistake:</strong> deploying to a platform with an ephemeral filesystem (most container-based PaaS providers) and only discovering uploaded files disappear after the next deploy. Set up object storage before launch, not after the first lost upload.</div>\n</section>\n<section class=\"step\" id=\"s14\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-info\">14</div>\n<h2>Gunicorn / uWSGI / ASGI</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>An application server runs multiple worker processes to handle concurrent requests, which the Django development server cannot do safely under real load.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n</div>\n<pre>pip install gunicorn\npip freeze &gt; requirements.txt\n\ngunicorn core.wsgi:application \\\n --workers 4 \\\n --bind 0.0.0.0:8000 \\\n --timeout 30 \\\n --access-logfile - \\\n --error-logfile -</pre>\n</div>\n<div class=\"step-body\">\n<p>A reasonable starting point for worker count is <code>(2 * CPU cores) + 1</code>. Too few workers queues requests under load, too many wastes memory and can starve the database connection pool.</p>\n</div>\n<table>\n<tr><th>Server</th><th>Use case</th></tr>\n<tr><td><code>gunicorn</code></td><td>Standard WSGI server, the most common default for Django</td></tr>\n<tr><td><code>uwsgi</code></td><td>More configuration knobs, common in older or Nginx-native stacks</td></tr>\n<tr><td><code>uvicorn</code> / <code>daphne</code></td><td>ASGI servers, required for Django Channels, WebSockets, or async views</td></tr>\n</table>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n<span class=\"code-file\">ASGI example with uvicorn, for async-heavy apps</span>\n</div>\n<pre>pip install uvicorn\nuvicorn core.asgi:application --host 0.0.0.0 --port 8000 --workers 4</pre>\n</div>\n<div class=\"tone-tip\"><strong>Tip:</strong> set <code>--timeout</code> deliberately. Too low kills slow-but-legitimate requests (large report generation, file processing), too high lets one stuck worker hang indefinitely and starve capacity for everyone else.</div>\n</section>\n<section class=\"step\" id=\"s15\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-info\">15</div>\n<h2>Nginx reverse proxy</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Nginx sits in front of Gunicorn to terminate TLS, serve static and media files efficiently, and protect the app server from slow clients and basic abuse, none of which Gunicorn is optimized to do itself.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Text</span>\n<span class=\"code-file\">/etc/nginx/sites-available/myproject</span>\n</div>\n<pre>server {\n listen 80;\n server_name yourdomain.com www.yourdomain.com;\n return 301 https://$host$request_uri;\n}\n\nserver {\n listen 443 ssl http2;\n server_name yourdomain.com www.yourdomain.com;\n\n ssl_certificate /etc/letsencrypt/live/yourdomain.com/fullchain.pem;\n ssl_certificate_key /etc/letsencrypt/live/yourdomain.com/privkey.pem;\n\n client_max_body_size 20M;\n\n location /static/ {\n alias /opt/myproject/staticfiles/;\n expires 30d;\n add_header Cache-Control \"public, immutable\";\n }\n location /media/ {\n alias /opt/myproject/media/;\n expires 7d;\n }\n location / {\n proxy_pass http://127.0.0.1:8000;\n proxy_set_header Host $host;\n proxy_set_header X-Real-IP $remote_addr;\n proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\n proxy_set_header X-Forwarded-Proto $scheme;\n proxy_read_timeout 30s;\n }\n}</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n<span class=\"code-file\">free TLS certificate with Certbot</span>\n</div>\n<pre>sudo apt install certbot python3-certbot-nginx\nsudo certbot --nginx -d yourdomain.com -d www.yourdomain.com\n<span># certbot also configures auto-renewal via a systemd timer</span></pre>\n</div>\n<div class=\"tone-danger\"><strong>Common mistake:</strong> forgetting <code>client_max_body_size</code>. Nginx defaults to a 1MB request body limit, so file upload forms will fail with a 413 error until this is raised to match your app's actual upload limits.</div>\n</section>\n<section class=\"step\" id=\"s16\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-info\">16</div>\n<h2>Systemd process management</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Gunicorn started directly in a terminal dies the moment that terminal closes or the server reboots. A process manager keeps it running, restarts it on crash, and starts it automatically on boot.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Text</span>\n<span class=\"code-file\">/etc/systemd/system/myproject.service</span>\n</div>\n<pre>[Unit]\nDescription=Gunicorn daemon for myproject\nAfter=network.target postgresql.service\n\n[Service]\nUser=www-data\nGroup=www-data\nWorkingDirectory=/opt/myproject\nEnvironmentFile=/opt/myproject/.env\nExecStart=/opt/myproject/venv/bin/gunicorn \\\n core.wsgi:application \\\n --workers 4 \\\n --bind unix:/opt/myproject/myproject.sock \\\n --access-logfile /var/log/myproject/access.log \\\n --error-logfile /var/log/myproject/error.log\nRestart=on-failure\nRestartSec=5\n\n[Install]\nWantedBy=multi-user.target</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n</div>\n<pre>sudo systemctl daemon-reload\nsudo systemctl enable myproject <span># start automatically on boot</span>\nsudo systemctl start myproject\nsudo systemctl status myproject <span># check it is running</span>\n\n<span># after a deploy, reload the workers without dropping connections</span>\nsudo systemctl reload myproject</pre>\n</div>\n<div>Binding to a Unix socket (<code>unix:/opt/myproject/myproject.sock</code>) instead of a TCP port is slightly faster and avoids exposing the app server on a network port at all, Nginx talks to it directly over the filesystem.</div>\n</section>\n<section class=\"step\" id=\"s17\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-info\">17</div>\n<h2>Dockerizing Django</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Containers guarantee the exact same runtime (Python version, system libraries, dependencies) in development, CI, and production, eliminating an entire category of environment-mismatch bugs.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Dockerfile</span>\n</div>\n<pre>FROM python:3.12-slim\n\nENV PYTHONDONTWRITEBYTECODE=1 \\\n PYTHONUNBUFFERED=1\n\nWORKDIR /app\n\nRUN apt-get update &amp;&amp; apt-get install -y --no-install-recommends \\\n libpq-dev gcc \\\n &amp;&amp; rm -rf /var/lib/apt/lists/*\n\nCOPY requirements.txt .\nRUN pip install --no-cache-dir -r requirements.txt\n\nCOPY . .\n\nRUN python manage.py collectstatic --noinput\n\nEXPOSE 8000\nCMD [\"gunicorn\", \"core.wsgi:application\", \"--bind\", \"0.0.0.0:8000\", \"--workers\", \"4\"]</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">YAML</span>\n<span class=\"code-file\">docker-compose.yml</span>\n</div>\n<pre>services:\n web:\n build: .\n command: gunicorn core.wsgi:application --bind 0.0.0.0:8000\n env_file: .env\n depends_on:\n - db\n ports:\n - \"8000:8000\"\n volumes:\n - static_volume:/app/staticfiles\n - media_volume:/app/media\n\n db:\n image: postgres:16-alpine\n environment:\n POSTGRES_DB: myproject\n POSTGRES_USER: myproject\n POSTGRES_PASSWORD: ${DB_PASSWORD}\n volumes:\n - postgres_data:/var/lib/postgresql/data\n\nvolumes:\n postgres_data:\n static_volume:\n media_volume:</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n</div>\n<pre>docker compose up --build -d\ndocker compose exec web python manage.py migrate\ndocker compose exec web python manage.py createsuperuser</pre>\n</div>\n<div class=\"tone-tip\"><strong>Tip:</strong> use a multi-stage build to keep the final image small, install build-only dependencies (like a compiler) in an earlier stage and copy just the compiled artifacts into the final, slim runtime image.</div>\n<div class=\"tone-danger\"><strong>Common mistake:</strong> running <code>collectstatic</code> only inside the Dockerfile build step but mounting a volume over <code>/app/staticfiles</code> at runtime, which silently hides the collected files. Decide once whether static files are baked into the image or collected at container startup, and stay consistent.</div>\n</section>\n<section class=\"step\" id=\"s18\">\n<div class=\"step-header\">\n<div class=\"step-badge\">18</div>\n<h2>CI/CD with GitHub Actions</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Automated tests and checks running before every merge catch the bugs and misconfigurations this entire guide is meant to prevent, before they ever reach a server.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">YAML</span>\n<span class=\"code-file\">.github/workflows/ci.yml</span>\n</div>\n<pre>name: CI\n\non:\n push:\n branches: [main]\n pull_request:\n branches: [main]\n\njobs:\n test:\n runs-on: ubuntu-latest\n services:\n postgres:\n image: postgres:16\n env:\n POSTGRES_PASSWORD: postgres\n POSTGRES_DB: test_db\n ports: [\"5432:5432\"]\n options: &gt;-\n --health-cmd pg_isready\n --health-interval 10s\n\n steps:\n - uses: actions/checkout@v4\n\n - uses: actions/setup-python@v5\n with:\n python-version: \"3.12\"\n\n - run: pip install -r requirements.txt\n\n - name: Run migrations check\n run: python manage.py makemigrations --check --dry-run\n\n - name: Run deploy checks\n run: python manage.py check --deploy\n env:\n DJANGO_SETTINGS_MODULE: core.settings.production\n SECRET_KEY: ci-test-key-not-used-in-prod\n ALLOWED_HOSTS: localhost\n DATABASE_URL: postgres://postgres:postgres@localhost:5432/test_db\n\n - name: Run tests\n run: python manage.py test\n env:\n DATABASE_URL: postgres://postgres:postgres@localhost:5432/test_db</pre>\n</div>\n<div>Add a second job that only runs on pushes to <code>main</code> and triggers the actual deploy (SSH into the server, or call your PaaS provider's deploy hook) only after the test job passes. This guarantees nothing broken ever reaches production automatically.</div>\n</section>\n<section class=\"step\" id=\"s19\">\n<div class=\"step-header\">\n<div class=\"step-badge\">19</div>\n<h2>PaaS deployment (Railway/Render)</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Managing your own Nginx, systemd, and OS patches is real ongoing work. A platform-as-a-service trades some control for speed, which is the right tradeoff for most small to mid-sized projects.</div>\n<div class=\"step-body\">\n<p>Most Python PaaS providers (Railway, Render, Heroku, Fly.io) follow the same basic recipe:</p>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Text</span>\n<span class=\"code-file\">Procfile (Heroku-style, also read by some other platforms)</span>\n</div>\n<pre>web: gunicorn core.wsgi:application --bind 0.0.0.0:$PORT\nrelease: python manage.py migrate</pre>\n</div>\n<div class=\"checklist\">\n<div class=\"check-item\"><div class=\"check-box\"></div><span>Add a managed PostgreSQL addon and copy the provided <code>DATABASE_URL</code> into your environment variables</span></div>\n<div class=\"check-item\"><div class=\"check-box\"></div><span>Set <code>SECRET_KEY</code>, <code>DEBUG=False</code>, and <code>ALLOWED_HOSTS</code> in the platform's environment variable settings, never in code</span></div>\n<div class=\"check-item\"><div class=\"check-box\"></div><span>Confirm the platform runs <code>collectstatic</code> automatically, or add it to a build/release step</span></div>\n<div class=\"check-item\"><div class=\"check-box\"></div><span>Point <code>release</code> or a post-deploy hook at <code>python manage.py migrate</code> so schema changes apply automatically on each deploy</span></div>\n<div class=\"check-item\"><div class=\"check-box\"></div><span>Add a custom domain and confirm the platform issues a TLS certificate for it automatically</span></div>\n</div>\n<div class=\"tone-tip\"><strong>Tip:</strong> on PaaS platforms, add WhiteNoise (Step 12) even if the platform also offers a CDN, it is a reliable fallback that requires zero platform-specific configuration.</div>\n</section>\n<section class=\"step\" id=\"s20\">\n<div class=\"step-header\">\n<div class=\"step-badge\">20</div>\n<h2>Zero-downtime deploys</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Restarting Gunicorn the naive way drops in-flight requests. A correct restart sequence swaps workers without a single failed request.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n<span class=\"code-file\">Gunicorn graceful reload</span>\n</div>\n<pre><span># sends SIGHUP: spins up new workers with new code, then retires old ones</span>\nkill -HUP $(cat /opt/myproject/gunicorn.pid)\n\n<span># or, with systemd, the equivalent:</span>\nsudo systemctl reload myproject</pre>\n</div>\n<div class=\"step-body\">\n<p>A typical deploy script sequence:</p>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n<span class=\"code-file\">deploy.sh</span>\n</div>\n<pre><span>#!/bin/bash</span>\n<span>set</span> -e\n\ngit pull origin main\nsource venv/bin/activate\npip install -r requirements.txt\npython manage.py check --deploy\npython manage.py migrate --noinput\npython manage.py collectstatic --noinput\nsudo systemctl reload myproject\n\n<span>echo</span> <span>\"Deploy complete.\"</span></pre>\n</div>\n<div class=\"tone-danger\"><strong>Common mistake:</strong> running a migration that locks a large table for an extended period during a zero-downtime deploy, which effectively causes downtime anyway despite the graceful worker reload. Test migration timing against a production-sized dataset in staging first.</div>\n</section>\n<section class=\"step\" id=\"s21\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-tip\">21</div>\n<h2>Logging and error tracking</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>With DEBUG=False, errors no longer show a traceback to the user, which is correct, but you still need to know an error happened. Without logging or error tracking, failures become invisible.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">core/settings/production.py</span>\n</div>\n<pre>LOGGING = {\n <span>\"version\"</span>: <span>1</span>,\n <span>\"disable_existing_loggers\"</span>: <span>False</span>,\n <span>\"handlers\"</span>: {\n <span>\"console\"</span>: {<span>\"class\"</span>: <span>\"logging.StreamHandler\"</span>},\n <span>\"file\"</span>: {\n <span>\"class\"</span>: <span>\"logging.handlers.RotatingFileHandler\"</span>,\n <span>\"filename\"</span>: <span>\"/var/log/myproject/django.log\"</span>,\n <span>\"maxBytes\"</span>: <span>10485760</span>,\n <span>\"backupCount\"</span>: <span>5</span>,\n },\n },\n <span>\"root\"</span>: {<span>\"handlers\"</span>: [<span>\"console\"</span>, <span>\"file\"</span>], <span>\"level\"</span>: <span>\"WARNING\"</span>},\n <span>\"loggers\"</span>: {\n <span>\"django\"</span>: {<span>\"handlers\"</span>: [<span>\"console\"</span>, <span>\"file\"</span>], <span>\"level\"</span>: <span>\"INFO\"</span>, <span>\"propagate\"</span>: <span>False</span>},\n },\n}</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n<span class=\"code-file\">Sentry, recommended for real-time error alerts</span>\n</div>\n<pre>pip install sentry-sdk\npip freeze &gt; requirements.txt</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n</div>\n<pre><span>import</span> sentry_sdk\n<span>from</span> sentry_sdk.integrations.django <span>import</span> DjangoIntegration\n\nsentry_sdk.<span>init</span>(\n dsn=config(<span>\"SENTRY_DSN\"</span>),\n integrations=[DjangoIntegration()],\n traces_sample_rate=<span>0.1</span>,\n send_default_pii=<span>False</span>,\n)</pre>\n</div>\n<div>Sentry captures the full stack trace, the request that triggered it, and notifies you in real time, without ever exposing that detail to the actual visitor. This is the production equivalent of the browser traceback you lose by setting DEBUG=False.</div>\n</section>\n<section class=\"step\" id=\"s22\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-tip\">22</div>\n<h2>Performance and caching</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>A correctly deployed Django app can still be slow. Caching and query optimization are what take a working production site to a fast one.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n<span class=\"code-file\">Redis-backed cache</span>\n</div>\n<pre>pip install django-redis\npip freeze &gt; requirements.txt</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n</div>\n<pre>CACHES = {\n <span>\"default\"</span>: {\n <span>\"BACKEND\"</span>: <span>\"django_redis.cache.RedisCache\"</span>,\n <span>\"LOCATION\"</span>: config(<span>\"REDIS_URL\"</span>),\n }\n}\nSESSION_ENGINE = <span>\"django.contrib.sessions.backends.cache\"</span>\nSESSION_CACHE_ALIAS = <span>\"default\"</span></pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">Caching an expensive view</span>\n</div>\n<pre><span>from</span> django.views.decorators.cache <span>import</span> cache_page\n\n<span>@cache_page</span>(<span>60</span> * <span>15</span>) <span># cache the rendered response for 15 minutes</span>\n<span>def</span> <span>post_list</span>(request):\n ...</pre>\n</div>\n<div class=\"step-body\">\n<p>Before reaching for caching, fix the underlying query cost. The most common production slowdown is the N+1 query problem, where a loop triggers one database hit per iteration.</p>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n</div>\n<pre><span># N+1: one query per post to fetch its author</span>\nposts = Post.objects.<span>all</span>()\n\n<span># fixed: one extra JOIN query total, regardless of post count</span>\nposts = Post.objects.<span>select_related</span>(<span>\"author\"</span>).<span>prefetch_related</span>(<span>\"tags\"</span>)</pre>\n</div>\n<div class=\"tone-tip\"><strong>Tip:</strong> install <code>django-debug-toolbar</code> in a staging environment with production-like data volume and check the SQL panel on your slowest pages before optimizing blindly, fix the queries that actually show up as expensive.</div>\n</section>\n<section class=\"step\" id=\"s23\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-tip\">23</div>\n<h2>Scaling beyond one server</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>A single server eventually hits a ceiling. Knowing the standard scaling path avoids painful, rushed architecture changes during a traffic spike.</div>\n<div class=\"step-body\">\n<p>The typical order of operations as traffic grows:</p>\n</div>\n<div class=\"checklist\">\n<div class=\"check-item\"><div class=\"check-box\"></div><span><strong>Vertical scaling first</strong>: increase the existing server's CPU and RAM, the simplest option with no architecture change</span></div>\n<div class=\"check-item\"><div class=\"check-box\"></div><span><strong>Add a read replica</strong>: route read-heavy queries to a PostgreSQL replica, keep writes on the primary</span></div>\n<div class=\"check-item\"><div class=\"check-box\"></div><span><strong>Add Redis caching</strong>: from Step 22, to reduce repeated database load for unchanging content</span></div>\n<div class=\"check-item\"><div class=\"check-box\"></div><span><strong>Move to multiple app servers</strong> behind a load balancer, since static sessions and media already live outside the app server (Steps 12-13), this becomes a straightforward horizontal add</span></div>\n<div class=\"check-item\"><div class=\"check-box\"></div><span><strong>Offload background work</strong> to Celery with Redis or RabbitMQ as a broker, so slow tasks (emails, report generation, image processing) never block a web request</span></div>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">Example: moving an email send to a background task</span>\n</div>\n<pre><span>from</span> celery <span>import</span> shared_task\n\n<span>@shared_task</span>\n<span>def</span> <span>send_welcome_email</span>(user_id):\n user = User.objects.<span>get</span>(pk=user_id)\n <span>send_mail</span>(<span>\"Welcome\"</span>, <span>\"Thanks for signing up.\"</span>, <span>\"noreply@yourdomain.com\"</span>, [user.email])\n\n<span># in the view: fires async, response returns immediately</span>\nsend_welcome_email.<span>delay</span>(user.id)</pre>\n</div>\n<div class=\"tone-danger\"><strong>Common mistake:</strong> reaching for Kubernetes or microservices before exhausting the simpler steps above. A single well-tuned Django monolith with caching and a background task queue comfortably serves a large amount of traffic, scale architecture complexity only when you have evidence it is actually needed.</div>\n</section>\n<section class=\"step\" id=\"s24\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-tip\">24</div>\n<h2>Maintenance and rollbacks</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Something will eventually break in production. A planned rollback path turns an incident into a five-minute fix instead of an all-night debugging session.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n<span class=\"code-file\">Code rollback, assuming tagged releases</span>\n</div>\n<pre>git checkout v1.4.2\nsudo systemctl reload myproject</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n<span class=\"code-file\">Reversing a migration</span>\n</div>\n<pre><span># roll back blog app to the previous migration</span>\npython manage.py migrate blog 0011_previous_migration</pre>\n</div>\n<div class=\"step-body\">\n<p>For planned maintenance, take the site into a maintenance state instead of letting users hit a generic error:</p>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Text</span>\n<span class=\"code-file\">Nginx maintenance mode toggle</span>\n</div>\n<pre>location / {\n if (-f /opt/myproject/maintenance.flag) {\n return 503;\n }\n proxy_pass http://127.0.0.1:8000;\n}\n\nerror_page 503 /maintenance.html;\nlocation = /maintenance.html {\n root /opt/myproject/static_pages;\n}</pre>\n</div>\n<div class=\"tone-tip\"><strong>Tip:</strong> keep a runbook, a short written document listing exact commands for rollback, restart, and maintenance mode. During an actual incident is the worst time to be reconstructing these steps from memory.</div>\n</section>\n<section class=\"step\" id=\"s25\">\n<div class=\"step-header\">\n<div class=\"step-badge\">25</div>\n<h2>Final launch checklist</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>A single consolidated list to run through right before the first real launch, and before every major release after that.</div>\n<div class=\"checklist\">\n<div class=\"check-item\"><div class=\"check-box\"></div><span><code>DEBUG = False</code> confirmed in the production settings module</span></div>\n<div class=\"check-item\"><div class=\"check-box\"></div><span><code>SECRET_KEY</code> is unique, long, and stored as an environment variable, not in source control</span></div>\n<div class=\"check-item\"><div class=\"check-box\"></div><span><code>ALLOWED_HOSTS</code> lists only the real production domain(s)</span></div>\n<div class=\"check-item\"><div class=\"check-box\"></div><span><code>python manage.py check --deploy</code> returns zero warnings</span></div>\n<div class=\"check-item\"><div class=\"check-box\"></div><span>HTTPS is enforced with a valid certificate and auto-renewal configured</span></div>\n<div class=\"check-item\"><div class=\"check-box\"></div><span>Database is PostgreSQL, with daily automated backups confirmed and a restore tested</span></div>\n<div class=\"check-item\"><div class=\"check-box\"></div><span><code>collectstatic</code> has run and static assets load correctly with no 404s</span></div>\n<div class=\"check-item\"><div class=\"check-box\"></div><span>Media uploads are stored in object storage, not local ephemeral disk</span></div>\n<div class=\"check-item\"><div class=\"check-box\"></div><span>Gunicorn is managed by systemd (or the platform equivalent) and restarts automatically on failure</span></div>\n<div class=\"check-item\"><div class=\"check-box\"></div><span>Error tracking (Sentry or equivalent) is wired up and a test error confirms it actually reports</span></div>\n<div class=\"check-item\"><div class=\"check-box\"></div><span>Logging is writing to a persistent location, not just stdout in a container that gets discarded</span></div>\n<div class=\"check-item\"><div class=\"check-box\"></div><span>CI runs tests, migration checks, and deploy checks on every pull request</span></div>\n<div class=\"check-item\"><div class=\"check-box\"></div><span>A documented rollback procedure exists and at least one person besides you knows it</span></div>\n<div class=\"check-item\"><div class=\"check-box\"></div><span>Admin URL is not the default <code>/admin/</code> path, or is otherwise protected (IP allowlist, extra auth)</span></div>\n<div class=\"check-item\"><div class=\"check-box\"></div><span>A superuser account exists with a strong, unique password, not a default credential</span></div>\n</div>\n<div>Treat this checklist as a recurring pre-release ritual, not a one-time task. Print it, paste it into your team's deploy template, or turn it into an automated CI gate, whichever keeps it from being skipped under deadline pressure.</div>\n</section>\n<section id=\"cheatsheet\">\n<h2>Deployment Cheat Sheet</h2>\n<p class=\"section-sub\">Quick-reference commands, settings, and production patterns.</p>\n<div class=\"cheat-grid\">\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\"><span></span><h3>Pre-deploy Commands</h3></div>\n<div class=\"cheat-card-body\">\n<div class=\"cheat-item\"><code>check --deploy</code><span>Audit settings for production readiness</span></div>\n<div class=\"cheat-item\"><code>makemigrations --check --dry-run</code><span>Fail if migrations are missing</span></div>\n<div class=\"cheat-item\"><code>migrate --plan</code><span>Preview migrations before applying them</span></div>\n<div class=\"cheat-item\"><code>collectstatic --noinput</code><span>Gather static files into STATIC_ROOT</span></div>\n<div class=\"cheat-item\"><code>test</code><span>Run the project's test suite</span></div>\n<div class=\"cheat-item\"><code>dumpdata / loaddata</code><span>Export and import database fixtures</span></div>\n</div>\n</div>\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\"><span></span><h3>Critical Security Settings</h3></div>\n<div class=\"cheat-card-body\">\n<div class=\"cheat-item\"><code>DEBUG = False</code><span>Never True in production, no exceptions</span></div>\n<div class=\"cheat-item\"><code>ALLOWED_HOSTS</code><span>Exact domain list, never a wildcard</span></div>\n<div class=\"cheat-item\"><code>SECURE_SSL_REDIRECT</code><span>Force HTTPS on every request</span></div>\n<div class=\"cheat-item\"><code>SESSION_COOKIE_SECURE</code><span>Cookies only sent over HTTPS</span></div>\n<div class=\"cheat-item\"><code>SECURE_HSTS_SECONDS</code><span>Browser-enforced HTTPS, raise gradually</span></div>\n<div class=\"cheat-item\"><code>X_FRAME_OPTIONS = \"DENY\"</code><span>Blocks clickjacking via iframes</span></div>\n</div>\n</div>\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\"><span></span><h3>Process Management</h3></div>\n<div class=\"cheat-card-body\">\n<div class=\"cheat-item\"><code>systemctl start/stop/status</code><span>Control the Gunicorn service</span></div>\n<div class=\"cheat-item\"><code>systemctl reload</code><span>Graceful restart, no dropped requests</span></div>\n<div class=\"cheat-item\"><code>journalctl -u myproject -f</code><span>Tail logs for a systemd service</span></div>\n<div class=\"cheat-item\"><code>kill -HUP $(cat gunicorn.pid)</code><span>Manual graceful Gunicorn reload</span></div>\n<div class=\"cheat-item\"><code>nginx -t</code><span>Test Nginx config before reloading</span></div>\n<div class=\"cheat-item\"><code>systemctl reload nginx</code><span>Apply Nginx config changes</span></div>\n</div>\n</div>\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\"><span></span><h3>Database Operations</h3></div>\n<div class=\"cheat-card-body\">\n<div class=\"cheat-item\"><code>pg_dump</code><span>Backup a PostgreSQL database</span></div>\n<div class=\"cheat-item\"><code>pg_restore</code><span>Restore from a pg_dump backup</span></div>\n<div class=\"cheat-item\"><code>migrate app_name 0011</code><span>Roll back to a specific migration</span></div>\n<div class=\"cheat-item\"><code>conn_max_age=600</code><span>Reuse DB connections across requests</span></div>\n<div class=\"cheat-item\"><code>select_related()</code><span>Fix N+1 queries on ForeignKey lookups</span></div>\n<div class=\"cheat-item\"><code>prefetch_related()</code><span>Fix N+1 on M2M and reverse FK lookups</span></div>\n</div>\n</div>\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\"><span></span><h3>Docker</h3></div>\n<div class=\"cheat-card-body\">\n<div class=\"cheat-item\"><code>docker compose up --build -d</code><span>Build and start all services</span></div>\n<div class=\"cheat-item\"><code>docker compose exec web bash</code><span>Shell into the running web container</span></div>\n<div class=\"cheat-item\"><code>docker compose logs -f web</code><span>Tail logs from a service</span></div>\n<div class=\"cheat-item\"><code>docker compose down</code><span>Stop and remove containers</span></div>\n<div class=\"cheat-item\"><code>docker compose exec web python manage.py migrate</code><span>Run migrations inside the container</span></div>\n</div>\n</div>\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\"><span></span><h3>Monitoring &amp; Performance</h3></div>\n<div class=\"cheat-card-body\">\n<div class=\"cheat-item\"><code>sentry-sdk</code><span>Real-time error tracking and alerts</span></div>\n<div class=\"cheat-item\"><code>django-debug-toolbar</code><span>Inspect SQL queries in a dev/staging env</span></div>\n<div class=\"cheat-item\"><code>cache_page(60*15)</code><span>Cache an entire view's response</span></div>\n<div class=\"cheat-item\"><code>django-redis</code><span>Redis-backed cache and session storage</span></div>\n<div class=\"cheat-item\"><code>celery</code><span>Background task queue for slow operations</span></div>\n<div class=\"cheat-item\"><code>RotatingFileHandler</code><span>Persistent, size-capped log files</span></div>\n</div>\n</div>\n</div>\n</section>";

